128	/**
129	 * The permissions map is a bit map which defines which modes are available
130	 * to a user. The permissions groups map to linux groups in the following
131	 * way: subtract 1000. The remainder is the bit number.
132	 * Thus unix groups 1000, 1001, 1002 etc represent the permissions groups
133	 * default, config and admin respectively.
134	 *
135	 */
136	int set_permissions_map(void)
137	{
138	  gid_t group[10];
139	  int n, i;
140	  int perm_num;
141	  // get the number of supplementary group IDs
142	  n = getgroups(10, group);
143	
144	  // give show permissions even if user has none
145	  map_permissions = ADMIN_PERMISSION;
146	
147	  for (i=0; i<n; i++) {
148	    perm_num = group[i] - 1000;
149	
150	    if (perm_num < 0 || perm_num > 31) {
151	      continue;
152	    }
153	
154	    //map_permissions |= (1 << perm_num);
155	    map_permissions |= ((1 << (perm_num+1)) - 1);
156	  }
157	
158	  printf("[CLI] Permissions %04x for this session\n", map_permissions);
159	  return 0;
160	}
