129	/**
130	 * The permissions map is a bit map which defines which modes are available
131	 * to a user. The permissions groups map to linux groups in the following
132	 * way: subtract 1000. The remainder is the bit number.
133	 * Thus unix groups 1000, 1001, 1002 etc represent the permissions groups
134	 * default, config and admin respectively.
135	 *
136	 */
137	int set_permissions_map(void)
138	{
139	  gid_t group[10];
140	  int n, i;
141	  int perm_num;
142	  // get the number of supplementary group IDs
143	  n = getgroups(10, group);
144	
145	  // give show permissions even if user has none
146	  map_permissions = ADMIN_PERMISSION;
147	
148	  for (i=0; i<n; i++) {
149	    perm_num = group[i] - 1000;
150	
151	    if (perm_num < 0 || perm_num > 31) {
152	      continue;
153	    }
154	
155	    //map_permissions |= (1 << perm_num);
156	    map_permissions |= ((1 << (perm_num+1)) - 1);
157	  }
158	
159	  printf("[CLI] Permissions %04x for this session\n", map_permissions);
160	  return 0;
161	}
